import{_ as s,G as r,c as d,o as c,a6 as i,J as t,a as e,m as a,w as n}from"./chunks/framework.CS_FrCij.js";const S=JSON.parse('{"title":"Blodstatus","description":"Korta sammanfattningar med high yield information om vanliga prover på akuten och hur man tolkar.","frontmatter":{"title":"Blodstatus","description":"Korta sammanfattningar med high yield information om vanliga prover på akuten och hur man tolkar.","layout":"doc"},"headers":[],"relativePath":"laboratorieanalyser/blodstatus.md","filePath":"laboratorieanalyser/blodstatus.md","lastUpdated":null}'),u={name:"laboratorieanalyser/blodstatus.md"},m=i('<h1 id="blodstatus" tabindex="-1">Blodstatus <a class="header-anchor" href="#blodstatus" aria-label="Permalink to &quot;Blodstatus&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Inkluderar Hb, MCV, MCH, MCHC, Erc, och Leukocyter.</p></div><h3 id="hb-hemoglobin" tabindex="-1">Hb, hemoglobin <a class="header-anchor" href="#hb-hemoglobin" aria-label="Permalink to &quot;Hb, hemoglobin&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Referensvärden</p><p>Män: 117-153<br> Kvinnor: 134-170<br> [g/L] <br> Intraindividuell variation 3%.</p></div><p>Syrebärande metalloprotein i erytrocyten.<br></p>',5),h=a("ul",null,[a("li",null,"Kvantitativ markör för den syrebärande kapaciteten."),a("li",null,"Används för att diagnosticera anemi eller polycytemi."),a("li",null,"Hemoglobinet vittnar om hur mycket syre blodet kan bära medans kliniken säger oss huruvida patienten kan tolerera anemin.")],-1),k=a("h3",{id:"mcv-mch-mchc",tabindex:"-1"},[e("MCV, MCH, MCHC "),a("a",{class:"header-anchor",href:"#mcv-mch-mchc","aria-label":'Permalink to "MCV, MCH, MCHC"'},"​")],-1),b=a("div",{class:"info custom-block"},[a("p",{class:"custom-block-title"},"Referensvärden"),a("p",null,[e("MCV (mean corpuscular volume): 82-98 fL"),a("br"),e(" MCH (mean corpuscular hemoglobin): 27,1-33,3 pg"),a("br"),e(" MCHC (mean corpuscular hemoglobin concentration): 317-357 g/L"),a("br")])],-1),p=a("p",null,"Analyser av den röda blodcellens storlek, mängd hemoglobin, och concentrationen hemoglobin.",-1),f=i('<ul><li>MCHC har sällan värde kring diagnostik på akuten.</li><li>MCV hjälper oss särskilja på mikro-, normo-, och makroanemier.</li><li>↑MCV/MCH kan peka på alkoholism, hypotyreos, MDS, B12-/folatbrist, kompenserad hemolys (↑retikulocyter)</li><li>↓MCV/MCH kan peka på järnbrist (vanligast), hereditära tillstånd som talassemi och sfärocytos.</li></ul><h3 id="erytrocyter" tabindex="-1">ERYTROCYTER <a class="header-anchor" href="#erytrocyter" aria-label="Permalink to &quot;ERYTROCYTER&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Referensvärden</p><p>Män: 4,25-5,71<br> Kvinnor: 3,94-5,16<br> [x 10<sup>12</sup>/L]<br> Intraindividuell variation 3,2%.</p></div><p>Antal erytrocyter / volymenhet blod.</p>',4),_=i('<ul><li>Förhöjd vid kronisk hypoxi, polycytemia vera, dehydrering.</li><li>Sällan av större värde som enskilt prov men bidrar till helhetsbilden vid blodavvikelser.</li></ul><h3 id="leukocyter-lpk" tabindex="-1">LEUKOCYTER (LPK) <a class="header-anchor" href="#leukocyter-lpk" aria-label="Permalink to &quot;LEUKOCYTER (LPK)&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Referensvärden</p><p>3,5-8,8<br> [x 10<sup>12</sup>/L]<br> Intraindividuell variation 11%.</p></div><p>Totala mängd vita blodkroppar i cirkulationen. Utgörs av lymfocyter, monocyter, samt neutrofila, eosinofila, och basofila granulocyter. Normalt finns ungefär lika stor andel i marginalpoolen längs väggarna i mindre vener som i cirkulationspoolen. Förändringar i LPK beror oftast på variationen i antalet neutrofila granulocyter. Hög intraindividuell variation.</p><p>Stiger vid många tillstånd. T.ex. infektion, inflammation, kirurgisk stress, trauma, kortisonbehandling, fysisk ansträgning, rökning, etc.</p>',5),v=a("li",null,"Ska tolkas med försiktighet och aldrig isolerat. Eftersom LPK kan stiga av så många orsaker, sjuka som normala, gör den provet högst osäkert för att bedöma farliga infektioner eller andra farliga tillstånd.",-1),g=a("li",null,"Låg sensitivitet och specificitet för att särskilja på allvarlig bakteriell infektion och självläkande virala tillstånd.",-1),y=a("li",null,"Ett normalt LPK utesluter inte infektion och ett högt LPK bekräftar inte bakteriell infektion.",-1),T=a("li",null,'Betydligt sämre prov än CRP för "rule-in" och "rule-out". Tillför marginell ökning för CRP:s prediktiva värde.',-1),C=a("li",null,"Har ett stort värde vid diagnostik av blodmalignitet och benmärgsinsufficiens i kombination med B-celler (diff).",-1);function H(R,K,L,N,A,I){const l=r("gr"),o=r("Ref");return c(),d("div",null,[m,t(l,null,{default:n(()=>[e("KLINISK ANVÄNDBARHET")]),_:1}),e(),h,t(l,null,{default:n(()=>[e("AKUT BLODFÖRLUST OCH HEMODILUTION")]),_:1}),a("ul",null,[a("li",null,[t(l,null,{default:n(()=>[e("AKUT (MINUTER):")]),_:1}),e(" Ger sällan någon påverkan vid lätt eller måttlig blödning. Vid svår och snabb blodförlust kan blodvärdet minska som en konsekvens av volymförlust i kombination med snabbt kompensatoriskt volymskifte. Redan efter 30 minuter kan man se ett abnormalt Hb, exempelvis i traumasammanhang.")]),a("li",null,[t(l,null,{default:n(()=>[e("TIDIG (1-12h):")]),_:1}),e(" Hb:et minskar som hastigast 6-12h då den interstitiella transkapillära autotransfusionen nått maxhastighet.")]),a("li",null,[t(l,null,{default:n(()=>[e("NADIR (24-48h):")]),_:1}),e(" Hb:et når sin lägsta nivå (nadir) efter 24-48h.")]),a("li",null,[t(l,null,{default:n(()=>[e("VÄTSKA:")]),_:1}),e(" 1L kristalloid kan minska Hb:et upp till 10 g/L.")])]),k,b,p,t(l,null,{default:n(()=>[e("KLINISK ANDVÄNDBARHET")]),_:1}),f,t(l,null,{default:n(()=>[e("KLINISK ANDVÄNDBARHET")]),_:1}),_,t(l,null,{default:n(()=>[e("KLINISK ANVÄNDBARHET")]),_:1}),a("ul",null,[v,g,y,a("li",null,[e("Hos barn leder LPK ofta till många falskt negativa (missade diagnoser) och falskt positiva (onödiga åtgärder/bildundersökningar)."),t(o,{label:"1",citation:"Kemps, N. et al (2024).",url:"https://doi.org/10.1136/archdischild-2024-327493"}),e(" Ska således enbart användas vid specifika frågeställningar snarare än screening för allvarliga infektioner.")]),T,C])])}const V=s(u,[["render",H]]);export{S as __pageData,V as default};
